  ('elementary-d0d1b9a2-moex-00885', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '各機關之歲出分配預算，其計畫或業務科目之各用途別科目中有一科目之經費不足，而他科目有賸餘時， 得辦理流用，流用之規定為何？', '["流入數額不得超過原預算數額百分之二十，流出數額不得超過原預算數額百分之二十", "流入數額不得超過原預算數額百分之三十，流出數額不得超過原預算數額百分之三十", "得流用為立法院審議刪除或刪減之預算項目", "得流用為用人經費"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:50+00:00", "source_pdf_sha1": "b41f0a91a59d", "answer_pdf_sha1": "29407fcd2776", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00886', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '各分會計機關之事務簡單者，其原始憑證經下列何者簽名或蓋章後，得用作記帳憑證，免製傳票？', '["主辦會計人員及其佐理人員", "機關長官及主辦會計人員", "主辦會計人員及審計人員", "機關長官及審計人員"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:50+00:00", "source_pdf_sha1": "b41f0a91a59d", "answer_pdf_sha1": "29407fcd2776", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00887', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '下列有關決算編造之敘述，正確者有幾項？①各主管機關接到各機關決算，應即查核彙編，如發現其中', '["主管機關彙編各機關決算時，所 提出之修正事項，應通知原編造機關及審計機關", "特別預算之收支，應於執行期滿後，依會計法之規 定，編造其決算", "特別預算之收支，跨越兩個年度以上者，應由主管機關依決算法所定程序，分年編 送年度會計報告", "一項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:50+00:00", "source_pdf_sha1": "b41f0a91a59d", "answer_pdf_sha1": "29407fcd2776", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00888', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '公務或公營事業之會計事務，各帳目整理後，有關資產、負債性質各帳目之餘額，應如何處理？', '["分別結入歲入預算及經費預算之各種帳目", "結入總損益之各種帳目", "轉入下年度或下期各該帳目", "轉入準備"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:50+00:00", "source_pdf_sha1": "b41f0a91a59d", "answer_pdf_sha1": "29407fcd2776", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00889', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '各機關或基金應辦理結帳或結算的情形，不包括下列何者？', '["會計年度終了時", "主辦會計人員異動時", "機關裁撤或基金結束時", "有每月、每季或每半年結算一次之必要者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:50+00:00", "source_pdf_sha1": "b41f0a91a59d", "answer_pdf_sha1": "29407fcd2776", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00890', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '依審計法之規定，下列有關核定財務責任之敘述，何者錯誤？', '["各機關主辦及經辦出納人員簽發支票或給付現金，如查明有超過核准人員核准數額者，應負損害賠償 責任", "審計機關審核各機關會計簿籍或報告，如發現所載事項與原始憑證不符，致公款遭受損害者，該主辦 及經辦會計人員應負損害賠償責任", "各機關經管現金、票據、證券、財物或其他資產，如有其他意外事故而致損失者，經查明未盡善良管 理人應有之注意時，該主辦及經辦會計人員應負損害賠償責任", "各機關人員對於財務上行為應負之責任，非經審計機關審查決定，不得解除"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:50+00:00", "source_pdf_sha1": "b41f0a91a59d", "answer_pdf_sha1": "29407fcd2776", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00891', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '預算法對國營事業虧損填補之順序為何？①出資填補  ②折減資本  ③撥用未分配盈餘  ④撥用公積', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:50+00:00", "source_pdf_sha1": "b41f0a91a59d", "answer_pdf_sha1": "29407fcd2776", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00892', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '有關預算執行之限制，下列敘述何者正確？', '["各機關執行歲出分配預算遇經費有不足時，應報請上級主管機關同意，轉請中央主計機關核定，始得 動支第一預備金", "中央主計機關對於各機關執行預算，得視事實需要，隨時派員調查之", "各機關重大工程之投資計畫，超過6年未動用預算者，其預算應重新審查", "依法得出售之國有財產及股票，市價高於預算者，得依市價出售"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:50+00:00", "source_pdf_sha1": "b41f0a91a59d", "answer_pdf_sha1": "29407fcd2776", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00893', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '下列有關會計人員交代之敘述，何者錯誤？', '["主辦會計人員辦理交代，應由所在機關長官或其代表及上級機關主辦會計人員或其代表監交", "會計人員經解除或變更其職務者，應辦交代", "會計佐理人員辦理交代，應由主辦會計人員或其代表監交", "主辦會計人員應自後任接替之日起三日內交代清楚"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:50+00:00", "source_pdf_sha1": "b41f0a91a59d", "answer_pdf_sha1": "29407fcd2776", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
